1	package repository
2	
3	import (
4		"context"
5		"errors"
6		"fmt"
7		"time"
8	
9		"github.com/jackc/pgx/v5"
10		"github.com/jackc/pgx/v5/pgxpool"
11	
12		"github.com/harborworks/booking-hub/internal/domain"
13	)
14	
15	type IdempotencyRepository interface {
16		Get(ctx context.Context, key string) (*domain.IdempotencyRecord, error)
17		Put(ctx context.Context, rec *domain.IdempotencyRecord) error
18		DeleteExpired(ctx context.Context, before time.Time) (int64, error)
19	}
20	
21	type idemRepo struct{ pool *pgxpool.Pool }
22	
23	func NewIdempotencyRepository(pool *pgxpool.Pool) IdempotencyRepository {
24		return &idemRepo{pool: pool}
25	}
26	
27	func (r *idemRepo) Get(ctx context.Context, key string) (*domain.IdempotencyRecord, error) {
28		const q = `
29			SELECT key, user_id, request_hash, status_code, response_body, content_type, created_at, expires_at
30			FROM idempotency_keys WHERE key = $1
31		`
32		row := r.pool.QueryRow(ctx, q, key)
33		var rec domain.IdempotencyRecord
34		if err := row.Scan(&rec.Key, &rec.UserID, &rec.RequestHash, &rec.StatusCode, &rec.ResponseBody, &rec.ContentType, &rec.CreatedAt, &rec.ExpiresAt); err != nil {
35			if errors.Is(err, pgx.ErrNoRows) {
36				return nil, domain.ErrNotFound
37			}
38			return nil, err
39		}
40		return &rec, nil
41	}
42	
43	func (r *idemRepo) Put(ctx context.Context, rec *domain.IdempotencyRecord) error {
44		const q = `
45			INSERT INTO idempotency_keys (key, user_id, request_hash, status_code, response_body, content_type, created_at, expires_at)
46			VALUES ($1,$2,$3,$4,$5,$6,$7,$8)
47			ON CONFLICT (key) DO NOTHING
48		`
49		tag, err := r.pool.Exec(ctx, q,
50			rec.Key, rec.UserID, rec.RequestHash, rec.StatusCode,
51			rec.ResponseBody, rec.ContentType, rec.CreatedAt, rec.ExpiresAt,
52		)
53		if err != nil {
54			return fmt.Errorf("put idempotency: %w", err)
55		}
56		if tag.RowsAffected() == 0 {
57			// Already existed: caller should re-fetch and serve cached.
58			return domain.ErrConflict
59		}
60		return nil
61	}
62	
63	func (r *idemRepo) DeleteExpired(ctx context.Context, before time.Time) (int64, error) {
64		tag, err := r.pool.Exec(ctx, `DELETE FROM idempotency_keys WHERE expires_at < $1`, before)
65		if err != nil {
66			return 0, err
67		}
68		return tag.RowsAffected(), nil
69	}
70	
