1	package service
2	
3	import (
4		"context"
5		"errors"
6		"fmt"
7		"log/slog"
8		"time"
9	
10		"github.com/google/uuid"
11	
12		"github.com/harborworks/booking-hub/internal/domain"
13		"github.com/harborworks/booking-hub/internal/repository"
14	)
15	
16	// GroupBuyDefaults are the policy-mandated defaults for new group buys.
17	var GroupBuyDefaults = struct {
18		Threshold int
19		Deadline  time.Duration
20	}{
21		Threshold: 5,
22		Deadline:  24 * time.Hour,
23	}
24	
25	type GroupBuyService struct {
26		repo          repository.GroupBuyRepository
27		resources     repository.ResourceRepository
28		users         repository.UserRepository
29		notifications repository.NotificationRepository
30		log           *slog.Logger
31	}
32	
33	func NewGroupBuyService(
34		repo repository.GroupBuyRepository,
35		resources repository.ResourceRepository,
36		users repository.UserRepository,
37		notifications repository.NotificationRepository,
38		log *slog.Logger,
39	) *GroupBuyService {
40		return &GroupBuyService{repo: repo, resources: resources, users: users, notifications: notifications, log: log}
41	}
42	
43	type CreateGroupBuyInput struct {
44		OrganizerID uuid.UUID
45		ResourceID  uuid.UUID
46		Title       string
47		Description string
48		Threshold   int       // 0 → default 5
49		Capacity    int
50		StartsAt    time.Time
51		EndsAt      time.Time
52		Deadline    *time.Time // nil → starts_at - 1ns or now+24h, whichever is earlier
53	}
54	
55	// Create persists a new group buy with policy defaults filled in.
56	func (s *GroupBuyService) Create(ctx context.Context, in CreateGroupBuyInput) (*domain.GroupBuy, error) {
57		now := time.Now().UTC()
58	
59		if user, err := s.users.GetByID(ctx, in.OrganizerID); err != nil {
60			return nil, err
61		} else if user.IsBlacklisted {
62			return nil, errors.Join(domain.ErrBlacklisted, errors.New(user.BlacklistReason))
63		}
64	
65		if _, err := s.resources.Get(ctx, in.ResourceID); err != nil {
66			return nil, err
67		}
68	
69		threshold := in.Threshold
70		if threshold <= 0 {
71			threshold = GroupBuyDefaults.Threshold
72		}
73	
74		deadline := time.Time{}
75		if in.Deadline != nil {
76			deadline = in.Deadline.UTC()
77		} else {
78			deadline = now.Add(GroupBuyDefaults.Deadline)
79			if deadline.After(in.StartsAt) {
80				deadline = in.StartsAt
81			}
82		}
83	
84		g := &domain.GroupBuy{
85			ResourceID:  in.ResourceID,
86			OrganizerID: in.OrganizerID,
87			Title:       in.Title,
88			Description: in.Description,
89			Threshold:   threshold,
90			Capacity:    in.Capacity,
91			StartsAt:    in.StartsAt.UTC(),
92			EndsAt:      in.EndsAt.UTC(),
93			Deadline:    deadline,
94			Status:      domain.GroupBuyOpen,
95		}
96		if err := g.Validate(now); err != nil {
97			return nil, err
98		}
99		if err := s.repo.Create(ctx, g); err != nil {
100			return nil, err
101		}
102		s.log.Info("group buy created", "id", g.ID, "threshold", g.Threshold, "deadline", g.Deadline)
103		return g, nil
104	}
105	
106	// Join adds a participant. Oversell is impossible because the underlying
107	// repository performs an atomic optimistic-locked decrement and rejects
108	// races. Idempotency is enforced one layer up via the idempotency middleware.
109	func (s *GroupBuyService) Join(ctx context.Context, gbID, userID uuid.UUID, qty int) (*domain.GroupBuy, *domain.GroupBuyParticipant, error) {
110		user, err := s.users.GetByID(ctx, userID)
111		if err != nil {
112			return nil, nil, err
113		}
114		if user.IsBlacklisted {
115			return nil, nil, errors.Join(domain.ErrBlacklisted, errors.New(user.BlacklistReason))
116		}
117	
118		const maxRetries = 3
119		for attempt := 1; attempt <= maxRetries; attempt++ {
120			gb, part, err := s.repo.JoinAtomic(ctx, gbID, userID, qty)
121			if err == nil {
122				s.notifyOrganizerProgress(ctx, gb)
123				return gb, part, nil
124			}
125			if errors.Is(err, domain.ErrOptimisticLock) && attempt < maxRetries {
126				s.log.Info("optimistic lock retry", "group_buy", gbID, "attempt", attempt)
127				continue
128			}
129			return nil, nil, err
130		}
131		return nil, nil, fmt.Errorf("join group buy: exhausted retries")
132	}
133	
134	func (s *GroupBuyService) Get(ctx context.Context, id uuid.UUID) (*domain.GroupBuy, error) {
135		return s.repo.Get(ctx, id)
136	}
137	
138	func (s *GroupBuyService) Participants(ctx context.Context, id uuid.UUID) ([]domain.GroupBuyParticipant, error) {
139		return s.repo.ListParticipants(ctx, id)
140	}
141	
142	func (s *GroupBuyService) List(ctx context.Context, limit, offset int) ([]domain.GroupBuy, error) {
143		return s.repo.List(ctx, limit, offset)
144	}
145	
146	// Progress is the structured payload returned to the UI for real-time
147	// rendering. It is intentionally cheap to compute so it can be polled.
148	type Progress struct {
149		GroupBuyID     uuid.UUID `json:"group_buy_id"`
150		Threshold      int       `json:"threshold"`
151		Confirmed      int       `json:"confirmed"`
152		RemainingSlots int       `json:"remaining_slots"`
153		Capacity       int       `json:"capacity"`
154		Ratio          float64   `json:"ratio"`
155		ThresholdMet   bool      `json:"threshold_met"`
156		Deadline       time.Time `json:"deadline"`
157		SecondsLeft    int64     `json:"seconds_left"`
158		Status         string    `json:"status"`
159	}
160	
161	func (s *GroupBuyService) Progress(ctx context.Context, id uuid.UUID) (*Progress, error) {
162		g, err := s.repo.Get(ctx, id)
163		if err != nil {
164			return nil, err
165		}
166		now := time.Now().UTC()
167		left := int64(g.Deadline.Sub(now).Seconds())
168		if left < 0 {
169			left = 0
170		}
171		return &Progress{
172			GroupBuyID:     g.ID,
173			Threshold:      g.Threshold,
174			Confirmed:      g.Confirmed(),
175			RemainingSlots: g.RemainingSlots,
176			Capacity:       g.Capacity,
177			Ratio:          g.Progress(),
178			ThresholdMet:   g.ThresholdMet(),
179			Deadline:       g.Deadline,
180			SecondsLeft:    left,
181			Status:         string(g.Status),
182		}, nil
183	}
184	
185	// SweepExpired is a job step: any open or met group buy whose deadline has
186	// passed gets a terminal state assigned (finalized if threshold met, expired
187	// otherwise) and the organizer is notified.
188	func (s *GroupBuyService) SweepExpired(ctx context.Context) error {
189		now := time.Now().UTC()
190		expiring, err := s.repo.ListExpiringBefore(ctx, now)
191		if err != nil {
192			return err
193		}
194		for i := range expiring {
195			g := &expiring[i]
196			target := domain.GroupBuyExpired
197			if g.ThresholdMet() {
198				target = domain.GroupBuyFinalized
199			}
200			if err := s.repo.UpdateStatus(ctx, g.ID, target); err != nil {
201				s.log.Warn("sweep update failed", "id", g.ID, "error", err)
202				continue
203			}
204			_ = s.notifications.CreateNotification(ctx, &domain.Notification{
205				UserID: g.OrganizerID,
206				Kind:   "group_buy_" + string(target),
207				Title:  fmt.Sprintf("Group buy %q %s", g.Title, target),
208				Body:   fmt.Sprintf("%d / %d confirmed at deadline.", g.Confirmed(), g.Threshold),
209			})
210		}
211		return nil
212	}
213	
214	func (s *GroupBuyService) notifyOrganizerProgress(ctx context.Context, g *domain.GroupBuy) {
215		if !g.ThresholdMet() {
216			return
217		}
218		if g.Status != domain.GroupBuyMet {
219			return
220		}
221		_ = s.notifications.CreateNotification(ctx, &domain.Notification{
222			UserID: g.OrganizerID,
223			Kind:   "group_buy_threshold_met",
224			Title:  fmt.Sprintf("Group buy %q reached its threshold", g.Title),
225			Body:   fmt.Sprintf("%d / %d seats confirmed.", g.Confirmed(), g.Threshold),
226		})
227	}
228	
