104	func (r *groupBuyRepo) JoinAtomic(ctx context.Context, gbID, userID uuid.UUID, qty int) (*domain.GroupBuy, *domain.GroupBuyParticipant, error) {
105		if qty <= 0 {
106			qty = 1
107		}
108		tx, err := r.pool.BeginTx(ctx, pgx.TxOptions{IsoLevel: pgx.ReadCommitted})
109		if err != nil {
110			return nil, nil, fmt.Errorf("begin tx: %w", err)
111		}
112		defer func() { _ = tx.Rollback(ctx) }()
113	
114		// Read current state.
115		row := tx.QueryRow(ctx, `SELECT `+groupBuyColumns+` FROM group_buys WHERE id = $1`, gbID)
116		g, err := scanGroupBuy(row)
117		if err != nil {
118			if errors.Is(err, pgx.ErrNoRows) {
119				return nil, nil, domain.ErrNotFound
120			}
121			return nil, nil, err
122		}
123		if g.Status != domain.GroupBuyOpen && g.Status != domain.GroupBuyMet {
124			return nil, nil, errors.Join(domain.ErrConflict, fmt.Errorf("group buy is %s", g.Status))
125		}
126		now := time.Now().UTC()
127		if !g.Deadline.After(now) {
128			return nil, nil, domain.ErrDeadlinePassed
129		}
130		if g.RemainingSlots < qty {
131			return nil, nil, domain.ErrOversold
132		}
133	
134		// Optimistic-locked decrement: only succeeds if version unchanged.
135		const upd = `
136			UPDATE group_buys
137			SET remaining_slots = remaining_slots - $2,
138			    version         = version + 1,
139			    status          = CASE
140			        WHEN (capacity - (remaining_slots - $2)) >= threshold THEN 'met'
141			        ELSE status
142			    END,
143			    updated_at = NOW()
144			WHERE id = $1 AND version = $3 AND remaining_slots >= $2
145			RETURNING ` + groupBuyColumns
146		row = tx.QueryRow(ctx, upd, gbID, qty, g.Version)
147		updated, err := scanGroupBuy(row)
148		if err != nil {
149			if errors.Is(err, pgx.ErrNoRows) {
150				return nil, nil, domain.ErrOptimisticLock
151			}
152			return nil, nil, fmt.Errorf("decrement remaining_slots: %w", err)
153		}
154	
155		// Insert participant. Unique (group_buy_id, user_id) prevents double join.
156		part := &domain.GroupBuyParticipant{
157			ID:         uuid.New(),
158			GroupBuyID: gbID,
159			UserID:     userID,
160			Quantity:   qty,
161			JoinedAt:   now,
162		}
163		_, err = tx.Exec(ctx, `
164			INSERT INTO group_buy_participants (id, group_buy_id, user_id, quantity, joined_at)
165			VALUES ($1,$2,$3,$4,$5)
166		`, part.ID, part.GroupBuyID, part.UserID, part.Quantity, part.JoinedAt)
167		if err != nil {
168			// 23505 = unique_violation in pg
169			if isUniqueViolation(err) {
170				return nil, nil, domain.ErrAlreadyJoined
171			}
172			return nil, nil, fmt.Errorf("insert participant: %w", err)
173		}
174	
175		if err := tx.Commit(ctx); err != nil {
176			return nil, nil, err
177		}
178		return updated, part, nil
179	}
