164	// CSVValidationError describes one row that failed bulk validation.
165	type CSVValidationError struct {
166		Row    int    `json:"row"`
167		Field  string `json:"field"`
168		Reason string `json:"reason"`
169	}
170	
171	// ParsedResourceRow is one row that survived bulk validation. Exported so
172	// unit tests can assert on the parsed form without round-tripping through DB.
173	type ParsedResourceRow struct {
174		Name        string
175		Description string
176		Capacity    int
177	}
178	
179	// ValidateResourcesCSV is a pure function that performs all schema and row
180	// checks for a resource CSV import. It is intentionally side-effect free so
181	// unit tests can exercise every branch without a database. The contract is
182	// "all-or-nothing": when any row fails, the slice of validation errors is
183	// returned and `parsed` is empty.
184	func ValidateResourcesCSV(body io.Reader) (parsed []ParsedResourceRow, errs []CSVValidationError, fatal error) {
185		r := csv.NewReader(body)
186		r.TrimLeadingSpace = true
187		rows, err := r.ReadAll()
188		if err != nil {
189			return nil, nil, fmt.Errorf("parse csv: %w", err)
190		}
191		if len(rows) == 0 {
192			return nil, nil, errors.New("csv is empty")
193		}
194		header := rows[0]
195		colIdx := map[string]int{}
196		for i, h := range header {
197			colIdx[strings.ToLower(strings.TrimSpace(h))] = i
198		}
199		required := []string{"name", "description", "capacity"}
200		for _, c := range required {
201			if _, ok := colIdx[c]; !ok {
202				return nil, nil, fmt.Errorf("missing column %q", c)
203			}
204		}
205	
206		parsed = make([]ParsedResourceRow, 0, len(rows)-1)
207		seen := map[string]bool{}
208		for i := 1; i < len(rows); i++ {
209			row := rows[i]
210			if len(row) < len(header) {
211				errs = append(errs, CSVValidationError{Row: i + 1, Field: "*", Reason: "short row"})
212				continue
213			}
214			name := strings.TrimSpace(row[colIdx["name"]])
215			desc := strings.TrimSpace(row[colIdx["description"]])
216			capStr := strings.TrimSpace(row[colIdx["capacity"]])
217	
218			if name == "" {
219				errs = append(errs, CSVValidationError{Row: i + 1, Field: "name", Reason: "required"})
220				continue
221			}
222			if seen[strings.ToLower(name)] {
223				errs = append(errs, CSVValidationError{Row: i + 1, Field: "name", Reason: "duplicate within file"})
224				continue
225			}
226			seen[strings.ToLower(name)] = true
227	
228			capVal, err := strconv.Atoi(capStr)
229			if err != nil || capVal <= 0 {
230				errs = append(errs, CSVValidationError{Row: i + 1, Field: "capacity", Reason: "must be a positive integer"})
231				continue
232			}
233			parsed = append(parsed, ParsedResourceRow{Name: name, Description: desc, Capacity: capVal})
234		}
235	
236		if len(errs) > 0 {
237			return nil, errs, nil
238		}
239		return parsed, nil, nil
240	}
241	
242	// ImportResourcesCSV parses a CSV with the columns name,description,capacity,
243	// validates every row, and persists the surviving rows inside a single
244	// transaction. Any validation error or insert error rolls back the whole
245	// transaction; the returned `inserted` count is the number of rows actually
246	// committed (always 0 on the failure paths).
247	func (s *GovernanceService) ImportResourcesCSV(ctx context.Context, body io.Reader) (inserted int, errs []CSVValidationError, fatal error) {
248		parsed, validationErrs, fatal := ValidateResourcesCSV(body)
249		if fatal != nil {
250			return 0, nil, fatal
251		}
252		if len(validationErrs) > 0 {
253			return 0, validationErrs, nil
254		}
255	
256		rows := make([]domain.Resource, 0, len(parsed))
257		for _, p := range parsed {
258			rows = append(rows, domain.Resource{
259				Name:        p.Name,
260				Description: p.Description,
261				Capacity:    p.Capacity,
262			})
263		}
264	
265		// All-or-nothing transactional insert. If a row collides with an existing
266		// resource (unique name), the whole transaction is rolled back and the
267		// caller learns about it via fatal.
268		n, err := s.resources.InsertManyTx(ctx, rows)
269		if err != nil {
270			s.log.Warn("csv import rolled back", "error", err)
271			return 0, nil, fmt.Errorf("import rolled back: %w", err)
272		}
273		s.log.Info("csv import committed", "rows", n)
274		return n, nil, nil
275	}
276	
277	// ExportResourcesCSV writes resources as CSV to the supplied writer.
278	func (s *GovernanceService) ExportResourcesCSV(ctx context.Context, w io.Writer) error {
279		resources, err := s.resources.List(ctx)
280		if err != nil {
281			return err
282		}
283		cw := csv.NewWriter(w)
284		defer cw.Flush()
285		if err := cw.Write([]string{"id", "name", "description", "capacity"}); err != nil {
286			return err
287		}
288		for _, r := range resources {
289			if err := cw.Write([]string{r.ID.String(), r.Name, r.Description, strconv.Itoa(r.Capacity)}); err != nil {
290				return err
291			}
292		}
293		return cw.Error()
294	}
