88				continue
89			}
90			dump[table] = rows
91		}
92		body, err := json.MarshalIndent(map[string]any{
93			"kind":       kind,
94			"taken_at":   now,
95			"since":      since,
96			"row_counts": rowCounts(dump),
97			"tables":     dump,
98		}, "", "  ")
99		if err != nil {
