120	// updated_at column and `since` is non-zero, only newer rows are returned.
121	func (s *BackupService) dumpTable(ctx context.Context, table string, since time.Time) ([]map[string]any, error) {
122		q := "SELECT row_to_json(t) FROM " + table + " t"
123		args := []any{}
124		if !since.IsZero() && tableHasUpdatedAt(table) {
125			q += " WHERE updated_at > $1"
126			args = append(args, since)
127		}
128		rows, err := s.pool.Query(ctx, q, args...)
129		if err != nil {
130			return nil, err
131		}
132		defer rows.Close()
133		out := make([]map[string]any, 0, 64)
134		for rows.Next() {
135			var raw []byte
136			if err := rows.Scan(&raw); err != nil {
137				return nil, err
138			}
139			var m map[string]any
140			if err := json.Unmarshal(raw, &m); err != nil {
141				return nil, err
142			}
143			out = append(out, m)
144		}
145		return out, rows.Err()
146	}
