170	// most recent full plus every incremental written after it. The caller can
171	// inspect this list before invoking ApplyRestore.
172	func (s *BackupService) PlanRestore(ctx context.Context) ([]domain.Backup, error) {
173		full, err := s.repo.LastFull(ctx)
