20	type backupRepo struct{ pool *pgxpool.Pool }
21	
22	func NewBackupRepository(pool *pgxpool.Pool) BackupRepository {
23		return &backupRepo{pool: pool}
24	}
25	
26	func (r *backupRepo) Insert(ctx context.Context, b *domain.Backup) error {
27		if b.ID == uuid.Nil {
28			b.ID = uuid.New()
29		}
30		if b.TakenAt.IsZero() {
31			b.TakenAt = time.Now().UTC()
32		}
33		_, err := r.pool.Exec(ctx, `
34			INSERT INTO backups (id, kind, path, size_bytes, taken_at, detail)
35			VALUES ($1,$2,$3,$4,$5,$6)
36		`, b.ID, b.Kind, b.Path, b.SizeBytes, b.TakenAt, b.Detail)
37		return err
38	}
39	
40	func (r *backupRepo) List(ctx context.Context, limit int) ([]domain.Backup, error) {
41		if limit <= 0 || limit > 200 {
42			limit = 50
43		}
44		rows, err := r.pool.Query(ctx, `
45			SELECT id, kind, path, size_bytes, taken_at, detail
46			FROM backups ORDER BY taken_at DESC LIMIT $1
47		`, limit)
48		if err != nil {
49			return nil, err
50		}
51		defer rows.Close()
52		out := make([]domain.Backup, 0)
53		for rows.Next() {
54			var b domain.Backup
55			if err := rows.Scan(&b.ID, &b.Kind, &b.Path, &b.SizeBytes, &b.TakenAt, &b.Detail); err != nil {
56				return nil, err
57			}
58			out = append(out, b)
59		}
60		return out, rows.Err()
61	}
