55		sessions repository.SessionRepository,
56		captchas repository.CaptchaRepository,
57		log *slog.Logger,
58		cfg AuthSettings,
59	) *AuthService {
60		return &AuthService{users: users, sessions: sessions, captchas: captchas, log: log, cfg: cfg}
61	}
