63	// Settings exposes the configured timings (read-only).
64	func (s *AuthService) Settings() AuthSettings { return s.cfg }
65	
66	// ---------- registration ----------
67	
68	func (s *AuthService) Register(ctx context.Context, username, password string) (*domain.User, error) {
69		username = strings.TrimSpace(username)
70		if len(username) < 3 || len(username) > 64 {
71			return nil, errors.Join(domain.ErrInvalidInput, errors.New("username must be 3–64 characters"))
72		}
73		if err := domain.ValidatePassword(password); err != nil {
74			return nil, err
75		}
76	
77		if existing, err := s.users.GetByUsername(ctx, username); err == nil && existing != nil {
78			return nil, errors.Join(domain.ErrConflict, errors.New("username is already taken"))
79		} else if err != nil && !errors.Is(err, domain.ErrNotFound) {
80			return nil, err
81		}
82	
83		hash, err := bcrypt.GenerateFromPassword([]byte(password), s.cfg.BcryptCost)
84		if err != nil {
85			return nil, fmt.Errorf("hash password: %w", err)
86		}
87		u := &domain.User{
88			Username:     username,
89			PasswordHash: string(hash),
90		}
91		if err := s.users.Create(ctx, u); err != nil {
92			return nil, err
93		}
94		s.log.Info("user registered", "user_id", u.ID, "username", u.Username)
95		return u, nil
96	}
