1	package middleware
2	
3	import (
4		"errors"
5		"net/http"
6		"strings"
7	
8		"github.com/gin-gonic/gin"
9	
10		"github.com/harborworks/booking-hub/internal/domain"
11		"github.com/harborworks/booking-hub/internal/service"
12	)
13	
14	// SessionCookieName is the name of the cookie holding the opaque session id.
15	const SessionCookieName = "harborworks_session"
16	
17	// Context keys for the resolved user/session.
18	const (
19		ctxKeyUser    = "auth.user"
20		ctxKeySession = "auth.session"
21	)
22	
23	// Authenticator builds Gin middleware that resolves the session cookie into a
24	// *domain.User attached to the gin context. If `required` is true, missing or
25	// expired sessions short-circuit with 401. Used by both API and HTML routes.
26	func Authenticator(auth *service.AuthService, required bool) gin.HandlerFunc {
27		return func(c *gin.Context) {
28			cookie, err := c.Cookie(SessionCookieName)
29			if err != nil || cookie == "" {
30				if required {
31					wantsHTML(c)
32					return
33				}
34				c.Next()
35				return
36			}
37			user, sess, err := auth.ResolveSession(c.Request.Context(), cookie)
38			if err != nil {
39				// Clear the bad cookie regardless.
40				clearCookie(c)
41				if required {
42					switch {
43					case errors.Is(err, domain.ErrSessionExpired):
44						unauthorized(c, "session expired due to inactivity")
45					case errors.Is(err, domain.ErrUnauthorized):
46						unauthorized(c, "authentication required")
47					default:
48						unauthorized(c, "authentication error")
49					}
50					return
51				}
52				c.Next()
53				return
54			}
55			c.Set(ctxKeyUser, user)
56			c.Set(ctxKeySession, sess)
57			c.Next()
58		}
59	}
60	
61	// CurrentUser fetches the resolved user from the gin context, or nil.
62	func CurrentUser(c *gin.Context) *domain.User {
63		v, ok := c.Get(ctxKeyUser)
64		if !ok {
65			return nil
66		}
67		u, _ := v.(*domain.User)
68		return u
69	}
70	
71	// RequireNotBlacklisted is a gate handler that 403s if the current user is on
72	// the blacklist. Routes that should be hard-blocked for blacklisted users
73	// (notably booking creation) compose this after Authenticator(required=true).
74	func RequireNotBlacklisted() gin.HandlerFunc {
75		return func(c *gin.Context) {
76			u := CurrentUser(c)
77			if u == nil {
78				unauthorized(c, "authentication required")
79				return
80			}
81			if u.IsBlacklisted {
82				c.AbortWithStatusJSON(http.StatusForbidden, gin.H{
83					"error":  "user is blacklisted",
84					"reason": u.BlacklistReason,
85				})
86				return
87			}
88			c.Next()
89		}
90	}
91	
92	// RequirePasswordRotated blocks every endpoint except logout, /me, and the
93	// change-password endpoint when the current user's must_rotate_password
94	// flag is set. The seeded admin starts with this flag on so the operator
95	// is forced to set a real password before doing anything else.
96	func RequirePasswordRotated() gin.HandlerFunc {
97		const changePath = "/api/auth/change-password"
98		const logoutPath = "/api/auth/logout"
99		const mePath = "/api/auth/me"
100		return func(c *gin.Context) {
101			u := CurrentUser(c)
102			if u == nil || !u.MustRotatePassword {
103				c.Next()
104				return
105			}
106			switch c.Request.URL.Path {
107			case changePath, logoutPath, mePath:
108				c.Next()
109				return
110			}
111			c.AbortWithStatusJSON(http.StatusForbidden, gin.H{
112				"error": "password rotation required",
113				"hint":  "POST " + changePath + " with current_password + new_password",
114			})
115		}
116	}
117	
118	func unauthorized(c *gin.Context, msg string) {
119		c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": msg})
120	}
121	
122	func wantsHTML(c *gin.Context) {
123		// HTML pages get a redirect to /auth/login; API callers get JSON 401.
124		if isHTMLRoute(c) {
125			c.Redirect(http.StatusFound, "/auth/login")
126			c.Abort()
127			return
128		}
129		unauthorized(c, "authentication required")
130	}
131	
132	func isHTMLRoute(c *gin.Context) bool {
133		accept := c.GetHeader("Accept")
134		return c.Request.Method == http.MethodGet && (accept == "" || strings.Contains(accept, "text/html") || strings.Contains(accept, "*/*"))
135	}
136	
137	func clearCookie(c *gin.Context) {
138		c.SetCookie(SessionCookieName, "", -1, "/", "", false, true)
139	}
