17	// AnalyticsService is the entry point for emitting and querying analytics
18	// data. Pre-aggregation and anomaly detection are exposed as Run* methods so
19	// the jobs Runner can schedule them.
20	type AnalyticsService struct {
21		repo      repository.AnalyticsRepository
22		anonSalt  string
23		anomalyX  float64 // 3.0 by spec
24		log       *slog.Logger
25	}
26	
27	func NewAnalyticsService(repo repository.AnalyticsRepository, anonSalt string, log *slog.Logger) *AnalyticsService {
28		return &AnalyticsService{repo: repo, anonSalt: anonSalt, anomalyX: 3.0, log: log}
29	}
30	
31	// Anon returns the hashed identifier used in events. The hash survives a
32	// hard-deletion of the user but cannot be reversed without the salt.
33	func (s *AnalyticsService) Anon(userID uuid.UUID) string {
34		if userID == uuid.Nil {
35			return ""
36		}
37		h := sha256.Sum256([]byte(s.anonSalt + ":" + userID.String()))
38		return hex.EncodeToString(h[:])
39	}
40	
41	func (s *AnalyticsService) Track(ctx context.Context, eventType domain.AnalyticsEventType, targetType string, targetID uuid.UUID, userID uuid.UUID) error {
42		return s.repo.RecordEvent(ctx, &domain.AnalyticsEvent{
43			EventType:  eventType,
44			TargetType: targetType,
45			TargetID:   targetID,
46			UserAnon:   s.Anon(userID),
47		})
48	}
49	
50	func (s *AnalyticsService) TopSessions(ctx context.Context, days int, limit int) ([]domain.TopSession, error) {
51		if days <= 0 {
52			days = 7
53		}
54		since := time.Now().UTC().Add(-time.Duration(days) * 24 * time.Hour)
55		return s.repo.TopSessions(ctx, since, limit)
56	}
57	
58	// Trends returns 7 / 30 / 90 day daily trend buckets for an event type.
59	func (s *AnalyticsService) Trends(ctx context.Context, eventType domain.AnalyticsEventType) (map[int][]domain.TrendBucket, error) {
60		out := map[int][]domain.TrendBucket{}
61		for _, days := range []int{7, 30, 90} {
62			buckets, err := s.repo.Trend(ctx, eventType, days)
63			if err != nil {
64				return nil, err
65			}
66			out[days] = buckets
67		}
68		return out, nil
69	}
70	
71	func (s *AnalyticsService) Anomalies(ctx context.Context, limit int) ([]domain.AnomalyAlert, error) {
72		return s.repo.ListAnomalies(ctx, limit)
73	}
74	
75	// RunAggregation rolls raw events into the hourly table. Idempotent.
76	func (s *AnalyticsService) RunAggregation(ctx context.Context) error {
77		since := time.Now().UTC().Add(-2 * time.Hour) // catch the previous full hour
78		n, err := s.repo.AggregateRecent(ctx, since)
79		if err != nil {
80			return err
81		}
82		s.log.Debug("analytics aggregation", "events", n)
83		return nil
84	}
85	
86	// RunAnomalyDetection compares the previous hour against the trailing 7-day
87	// hourly average for each event type. If observed > 3x baseline (and baseline
88	// is non-trivial) an anomaly_alert row is inserted.
89	func (s *AnalyticsService) RunAnomalyDetection(ctx context.Context) error {
90		hour := time.Now().UTC().Truncate(time.Hour).Add(-time.Hour)
91		for _, et := range []domain.AnalyticsEventType{domain.EventView, domain.EventFavorite, domain.EventComment, domain.EventDownload} {
92			observed, err := s.repo.HourlyCount(ctx, et, hour)
93			if err != nil {
94				return err
95			}
96			baseline, err := s.repo.BaselineHourlyAverage(ctx, et, hour)
97			if err != nil {
98				return err
99			}
100			if baseline < 1 || observed == 0 {
101				continue
102			}
103			ratio := float64(observed) / baseline
104			if ratio > s.anomalyX {
105				alert := &domain.AnomalyAlert{
106					EventType: et,
107					Observed:  observed,
108					Baseline:  baseline,
109					Ratio:     ratio,
110					Detail:    fmt.Sprintf("hour=%s observed=%d baseline=%.2f", hour.Format(time.RFC3339), observed, baseline),
111				}
112				if err := s.repo.InsertAnomaly(ctx, alert); err != nil {
113					s.log.Warn("anomaly insert failed", "error", err)
114					continue
115				}
116				s.log.Warn("traffic anomaly detected", "event", et, "ratio", ratio, "observed", observed, "baseline", baseline)
117			}
118		}
119		return nil
120	}
121	
122	// AnonymiseUserEvents is invoked by the deletion executor to scrub any
123	// reference to a user from the events table. The hashed user_anon column is
124	// nulled out so historic counts remain intact.
125	func (s *AnalyticsService) AnonymiseUserEvents(ctx context.Context, userID uuid.UUID) error {
126		return s.repo.AnonymiseUserEvents(ctx, s.Anon(userID))
127	}
