196	// futureRFC3339 returns a UTC RFC3339 string n hours from now, truncated to
197	// the hour. Used to make booking timestamps deterministic.
198	func futureRFC3339(hours int) string {
199		t := time.Now().UTC().Add(time.Duration(hours) * time.Hour).Truncate(time.Hour)
200		return t.Format(time.RFC3339)
201	}
202	
203	// idemKey returns a unique idempotency key for a test invocation.
204	func idemKey(scope string) string {
205		return fmt.Sprintf("idem-%s-%d", scope, time.Now().UnixNano())
206	}
207	
208	// Resource UUIDs available from the seed file.
209	const (
210		SeedSlipA1     = "aaaa1111-0000-0000-0000-000000000001"
211		SeedSlipA2     = "aaaa1111-0000-0000-0000-000000000002"
212		SeedMooringM7  = "aaaa1111-0000-0000-0000-000000000003"
213		SeedConfRoom   = "bbbb2222-0000-0000-0000-000000000001"
214		SeedSunsetDeck = "bbbb2222-0000-0000-0000-000000000002"
215	)
216	
217	// containsAll asserts every needle appears somewhere in the haystack body.
218	// Used for ad-hoc text assertions when full JSON parsing would be heavyweight.
219	func containsAll(t *testing.T, body []byte, needles ...string) {
220		t.Helper()
221		s := string(body)
222		for _, n := range needles {
223			if !strings.Contains(s, n) {
224				t.Errorf("body missing %q\n--- body ---\n%s", n, s)
225			}
226		}
227	}
