{"replace_all": false, "file_path": "/home/mint/Desktop/projects/task-08/repo/internal/repository/groupbuy.go", "old_string": "func (r *groupBuyRepo) UpdateStatus(ctx context.Context, id uuid.UUID, status domain.GroupBuyStatus) error {", "new_string": "func (r *groupBuyRepo) MarkFailedAndReleaseSlots(ctx context.Context, id uuid.UUID) error {
	// One transaction so the status flip and the slot release commit
	// together. Without the BEGIN/COMMIT a crash between the two updates
	// would leave the row "failed" but with seats still consumed.
	tx, err := r.pool.BeginTx(ctx, pgx.TxOptions{IsoLevel: pgx.ReadCommitted})
	if err != nil {
		return fmt.Errorf("begin failed-release tx: %w", err)
	}
	defer func() { _ = tx.Rollback(ctx) }()

	const upd = `
		UPDATE group_buys
		   SET status          = 'failed',
		       remaining_slots = capacity,
		       version         = version + 1,
		       updated_at      = NOW()
		 WHERE id = $1
		   AND status IN ('open','met')
	`
	tag, err := tx.Exec(ctx, upd, id)
	if err != nil {
		return fmt.Errorf("mark failed: %w", err)
	}
	if tag.RowsAffected() == 0 {
		return domain.ErrNotFound
	}
	return tx.Commit(ctx)
}

func (r *groupBuyRepo) UpdateStatus(ctx context.Context, id uuid.UUID, status domain.GroupBuyStatus) error {"}

